scwin.onpageload = async function () {
  scwin.lobranCd = $c.gus.cfIsNull($p, $c.data.getMemInfo($p, "lobranCd")) ? "" : $c.data.getMemInfo($p, "lobranCd");
  scwin.vCurDate = $c.date.getServerDateTime($p, "yyyyMMdd"); // 서버를 기준으로 현재 날짜 반환
  scwin.subVcurDate = scwin.vCurDate.substring(0, 6);
  scwin.vwrkStDt = scwin.subVcurDate + "01"; // 입항예정일자 from(현재 날짜가 포함된 달의 시작 일자)
  scwin.vwrkEndDt = scwin.subVcurDate + $c.date.getLastDateOfMonth($p, scwin.subVcurDate); // 입항예정일자 to(현재 날짜가 포함된 달의 마지막 일자)

  scwin.del_staffNo = "";
  scwin.del_valueCheck = 0;
  scwin.del_occpgrdNm = "";
  scwin.del_occpgrdCd = 0;
  scwin.del_chief = 0;
  scwin.v_workClsCd = "";
  scwin.bOnPopUp = false;
  const codeOptions = [{
    grpCd: "OP316",
    compID: "acb_wrkPlClsCd"
  }];
  $c.data.setCommonCode($p, codeOptions, scwin.setCommonCodeCallBack);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
  $p.setTimeout(function () {
    scwin.f_initSetTab(); //tab세팅	
  }, {
    "delay": 50
  });
};
scwin.setCommonCodeCallBack = async function () {
  ds_combo1_search.set("sysCd", "BerthNonUsableEBC");
  ds_combo1_search.set("queryId", "retriveLobranCodeList");
  var rs = await $c.sbm.execute($p, sbm_combo1);
  if (rs.responseJSON.resultDataSet[0].Msg == "SUCC") {
    ds_combo1.setJSON(rs.responseJSON.GAUCE);
    ds_combo1.sort("code", 0);
  }
  ;
  acb_wrkPlClsCd.addItem("전체", "", "", 0);
  acb_wrkPlClsCd.setSelectedIndex(0);
  scwin.f_SetDefaultData();

  // acb_lobranCd.setValue("4AA");
  // // ica_wrkDt.setValue("202404");
  // ica_wrkDt.setValue("202112");
};

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function () {
  ica_wrkDt.setValue(scwin.vCurDate);
  acb_lobranCd.setValue(scwin.lobranCd);
  acb_lobranCd.focus();
};

