scwin.f_ClickEvent = function (row, colid) {
  var cnt_Weather = ds_extdWrk.getCellData(ds_extdWrk.getRowPosition(), "weatherCnt");
  var cnt_Single = ds_extdWrk.getCellData(ds_extdWrk.getRowPosition(), "singleCnt");
  var cnt_Emer = ds_extdWrk.getCellData(ds_extdWrk.getRowPosition(), "emerCnt");
  var cnt_Move = ds_extdWrk.getCellData(ds_extdWrk.getRowPosition(), "moveCnt");
  scwin.del_staffNo = ds_extdWrk.getCellData(ds_extdWrk.getRowPosition(), "staffNo");
  if (cnt_Weather == 0 && cnt_Single == 0 && cnt_Emer == 0 && cnt_Move == 0) return;
  if (ds_extdWrk.getCellData(row, "groupLv1") == "간부") {
    scwin.del_chief = 1;
  } else {
    scwin.del_chief = 0;
  }
  if (ds_extdWrk.getCellData(row, "occpgrdCd") == "" && scwin.del_chief == 0) {
    scwin.del_occpgrdCd = ds_extdWrk.getCellData(row - 1, "occpgrdCd"); //구분값이 간부인 값을 제외한 SUM행일 경우, 마지맥 행의 구분코드 가져와서 대입.
  } else {
    scwin.del_occpgrdCd = ds_extdWrk.getCellData(row, "occpgrdCd");
  }
  if (cnt_Weather != "" && colid == "weatherCnt") {
    scwin.del_valueCheck = 1;
    scwin.f_openDetailPopup();
  } else if (cnt_Single != "" && colid == "singleCnt") {
    scwin.del_valueCheck = 2;
    scwin.f_openDetailPopup();
  } else if (cnt_Emer != "" && colid == "emerCnt") {
    scwin.del_valueCheck = 3;
    scwin.f_openDetailPopup();
  } else if (cnt_Move != "" && colid == "moveCnt") {
    scwin.del_valueCheck = 4;
    scwin.f_openDetailPopup();
  }
};
scwin.gr_extdWrk_onsubtotaldblclick = function (info) {
  if (info.colID == "weatherCnt_s1" || info.colID == "singleCnt_s1" || info.colID == "emerCnt_s1" || info.colID == "moveCnt_s1") {
    var startRowIdx = info.startRowIndex;
    var endRowIdx = info.endRowIndex;
    var cnt_Weather = 0;
    var cnt_Single = 0;
    var cnt_Emer = 0;
    var cnt_Move = 0;
    for (var i = startRowIdx; i <= endRowIdx; i++) {
      cnt_Weather += $c.gus.cfIsNull($p, ds_extdWrk.getCellData(i, "weatherCnt")) ? 0 : ds_extdWrk.getCellData(i, "weatherCnt") * 1;
      cnt_Single += $c.gus.cfIsNull($p, ds_extdWrk.getCellData(i, "singleCnt")) ? 0 : ds_extdWrk.getCellData(i, "singleCnt") * 1;
      cnt_Emer += $c.gus.cfIsNull($p, ds_extdWrk.getCellData(i, "emerCnt")) ? 0 : ds_extdWrk.getCellData(i, "emerCnt") * 1;
      cnt_Move += $c.gus.cfIsNull($p, ds_extdWrk.getCellData(i, "moveCnt")) ? 0 : ds_extdWrk.getCellData(i, "moveCnt") * 1;
    }
    scwin.del_staffNo = "";
    if (cnt_Weather == 0 && cnt_Single == 0 && cnt_Emer == 0 && cnt_Move == 0) return;
    if (ds_extdWrk.getCellData(info.startRowIndex, "groupLv1") == "간부") {
      scwin.del_chief = 1;
    } else {
      scwin.del_chief = 0;
    }
    if (ds_extdWrk.getCellData(info.endRowIndex, "occpgrdCd") == "" && scwin.del_chief == 0) {
      scwin.del_occpgrdCd = ds_extdWrk.getCellData(info.endRowIndex, "occpgrdCd"); //구분값이 간부인 값을 제외한 SUM행일 경우, 마지맥 행의 구분코드 가져와서 대입.
    } else {
      scwin.del_occpgrdCd = ds_extdWrk.getCellData(info.endRowIndex, "occpgrdCd");
    }
    if (cnt_Weather != "" && info.colID == "weatherCnt_s1") {
      scwin.del_valueCheck = 1;
      scwin.f_openDetailPopup();
    } else if (cnt_Single != "" && info.colID == "singleCnt_s1") {
      scwin.del_valueCheck = 2;
      scwin.f_openDetailPopup();
    } else if (cnt_Emer != "" && info.colID == "emerCnt_s1") {
      scwin.del_valueCheck = 3;
      scwin.f_openDetailPopup();
    } else if (cnt_Move != "" && info.colID == "moveCnt_s1") {
      scwin.del_valueCheck = 4;
      scwin.f_openDetailPopup();
    }
  }
  ;
};
